// ============================================================
// CDC → Titãs Sinergy D360  —  Field Mapping & Transformation
// ============================================================
// This node receives the full CDC API response and:
//  1. Maps CDC fields to the Sinergy schema
//  2. Calculates period metadata (diasDecorridos, diasMes)
//  3. Returns a plain JS object ready to be serialised to
//     the Firestore typed-value format in the next node.
//
// HOW TO ADAPT:
//   - Find every comment starting with "CDC field:" and
//     replace the placeholder paths with the real field
//     names from your CDC API response.
//   - The CDC response is available as $json.body (because
//     the HTTP Request node was set to return fullResponse).
// ============================================================

const cdcData = $input.first().json.body;
// If CDC returned an array at the root, use cdcData directly;
// if it's wrapped in a key, adjust accordingly, e.g.:
//   const cdcData = $input.first().json.body.data;

// ---- Period helpers ----------------------------------------
const now = new Date();
const year  = now.getFullYear();
const month = now.getMonth(); // 0-based
const day   = now.getDate();

const firstDay = new Date(year, month, 1);
const lastDay  = new Date(year, month + 1, 0);

const pad = (n) => String(n).padStart(2, '0');
const fmtDate = (d) => `${pad(d.getDate())}/${pad(d.getMonth()+1)}/${d.getFullYear()}`;

const periodo        = `${fmtDate(firstDay)} – ${fmtDate(lastDay)}`;
const diasDecorridos = day;
// CDC field: (calculated locally — not from CDC)
const diasMes        = lastDay.getDate();

// ---- Helper: safely read a CDC numeric field ---------------
// Usage: cdcNum(cdcData, 'vendas.total_bruto')
function cdcNum(obj, path, fallback = 0) {
  const parts = path.split('.');
  let cur = obj;
  for (const p of parts) {
    if (cur == null || typeof cur !== 'object') return fallback;
    cur = cur[p];
  }
  return typeof cur === 'number' ? cur : (parseFloat(cur) || fallback);
}

function cdcStr(obj, path, fallback = '') {
  const parts = path.split('.');
  let cur = obj;
  for (const p of parts) {
    if (cur == null || typeof cur !== 'object') return fallback;
    cur = cur[p];
  }
  return cur != null ? String(cur) : fallback;
}

// ---- Store mapping -----------------------------------------
// Each entry:
//   cdcKey    — the key CDC uses to identify the store inside
//               the response (e.g. inside cdcData.lojas or an
//               array of store objects).  ADJUST TO YOUR CDC.
//   siloKey   — the key used in the Sinergy schema.
//   label     — display name.
//   meta      — monthly target (keep hardcoded or pull from CDC).
//
// Assumed CDC structure per store object:
//   { id_loja, nome_loja, venda_total, qtd_pedidos,
//     qtd_cancelamentos, vendedores: [{nome, venda_total,
//     indice_performance, qtd_pedidos}],
//     acessorios: { total, vendedores: [{nome, venda_total}] } }
//
// ADAPT the cdcKey values and field paths below to match
// the real CDC response structure.

const storeMap = [
  { cdcKey: 'saomateus',    siloKey: 'saomateus',    label: 'São Mateus',     meta: 450000 },
  { cdcKey: 'cariacica',    siloKey: 'cariacica',    label: 'Cariacica',      meta: 450000 },
  { cdcKey: 'itabuna',      siloKey: 'itabuna',      label: 'Itabuna',        meta: 390000 },
  { cdcKey: 'barreiras',    siloKey: 'barreiras',    label: 'Barreiras',      meta: 280000 },
  { cdcKey: 'moxuara',      siloKey: 'moxuara',      label: 'Moxuara',        meta: 270000 },
  { cdcKey: 'teixeira',     siloKey: 'teixeira',     label: 'Teixeira',       meta: 225000 },
  { cdcKey: 'laranjeiras',  siloKey: 'laranjeiras',  label: 'Laranjeiras',    meta: 220000 },
  { cdcKey: 'serra',        siloKey: 'serra',        label: 'Serra',          meta: 210000 },
  { cdcKey: 'linhares',     siloKey: 'linhares',     label: 'Linhares',       meta: 210000 },
  { cdcKey: 'montserrat',   siloKey: 'montserrat',   label: 'Montserrat',     meta: 165000 },
  { cdcKey: 'praiadacosta', siloKey: 'praiadacosta', label: 'Praia da Costa', meta: 130000 }
];

// ---- Locate store data in CDC response --------------------
// CDC may return stores as a dict keyed by store id,
// or as an array.  Handle both:
function getCdcStore(cdcData, cdcKey) {
  // Option A: cdcData.lojas is a dict  → cdcData.lojas[cdcKey]
  if (cdcData.lojas && typeof cdcData.lojas === 'object' && !Array.isArray(cdcData.lojas)) {
    return cdcData.lojas[cdcKey] || {};
  }
  // Option B: cdcData.lojas is an array with id_loja field
  if (Array.isArray(cdcData.lojas)) {
    return cdcData.lojas.find(s => s.id_loja === cdcKey || s.nome_loja === cdcKey) || {};
  }
  // Option C: root is an array
  if (Array.isArray(cdcData)) {
    return cdcData.find(s => s.id_loja === cdcKey || s.nome_loja === cdcKey) || {};
  }
  return {};
}

// ---- Map top sellers for a store --------------------------
function mapTopSellers(cdcStore) {
  // CDC field: vendedores  → array of top seller objects
  const sellers = Array.isArray(cdcStore.vendedores) ? cdcStore.vendedores : [];
  return sellers.slice(0, 5).map(v => ({
    n: cdcStr(v, 'nome',              ''),   // CDC field: vendedores[].nome → n
    t: cdcNum(v, 'venda_total',       0),    // CDC field: vendedores[].venda_total → t
    i: cdcNum(v, 'indice_performance',0),    // CDC field: vendedores[].indice_performance → i
    p: cdcNum(v, 'qtd_pedidos',       0)     // CDC field: vendedores[].qtd_pedidos → p
  }));
}

// ---- Map accessories for a store -------------------------
function mapAcessorios(cdcStore) {
  // CDC field: acessorios.total → acessorios.total
  const acc = (cdcStore.acessorios && typeof cdcStore.acessorios === 'object')
    ? cdcStore.acessorios : {};
  const topAcc = Array.isArray(acc.vendedores) ? acc.vendedores : [];
  return {
    total: cdcNum(acc, 'total', 0),           // CDC field: acessorios.total → acessorios.total
    top: topAcc.slice(0, 5).map(v => ({
      n: cdcStr(v, 'nome',       ''),         // CDC field: acessorios.vendedores[].nome → n
      t: cdcNum(v, 'venda_total', 0)          // CDC field: acessorios.vendedores[].venda_total → t
    }))
  };
}

// ---- Build lojas object -----------------------------------
const lojas = {};
for (const sm of storeMap) {
  const cdcStore = getCdcStore(cdcData, sm.cdcKey);
  lojas[sm.siloKey] = {
    total:      cdcNum(cdcStore, 'venda_total',        0),   // CDC field: venda_total → total
    meta:       sm.meta,                                      // hardcoded (or: cdcNum(cdcStore,'meta',sm.meta))
    ped:        cdcNum(cdcStore, 'qtd_pedidos',        0),   // CDC field: qtd_pedidos → ped
    cancel:     cdcNum(cdcStore, 'qtd_cancelamentos',  0),   // CDC field: qtd_cancelamentos → cancel
    label:      sm.label,
    top:        mapTopSellers(cdcStore),
    acessorios: mapAcessorios(cdcStore)
  };
}

// ---- Subredes (static config — adjust gestores if needed) -
const subredes = {
  titas1: { nome: 'Titãs 1', gestor: 'Gestor T1', meta: 1240000, lojas: ['saomateus','cariacica','praiadacosta'] },
  titas2: { nome: 'Titãs 2', gestor: 'Gestor T2', meta:  725000, lojas: ['moxuara','laranjeiras','barreiras']    },
  titas3: { nome: 'Titãs 3', gestor: 'Gestor T3', meta: 1035000, lojas: ['teixeira','montserrat','serra','linhares','itabuna'] }
};

// ---- CDC network-level fields -----------------------------
// CDC field: meta_rede or meta_total → meta_rede
const meta_rede = cdcNum(cdcData, 'meta_rede', 3000000);

// ---- Final Sinergy document --------------------------------
const sinergyDoc = {
  periodo,
  diasDecorridos,
  diasMes,
  meta_rede,
  lojas,
  subredes
};

// ============================================================
// Convert plain JS → Firestore REST typed-value format
// ============================================================
function toFirestoreValue(value) {
  if (value === null || value === undefined) {
    return { nullValue: null };
  }
  if (typeof value === 'boolean') {
    return { booleanValue: value };
  }
  if (typeof value === 'number') {
    // Use integerValue for whole numbers, doubleValue otherwise
    if (Number.isInteger(value)) {
      return { integerValue: String(value) };
    }
    return { doubleValue: value };
  }
  if (typeof value === 'string') {
    return { stringValue: value };
  }
  if (Array.isArray(value)) {
    return {
      arrayValue: {
        values: value.map(toFirestoreValue)
      }
    };
  }
  if (typeof value === 'object') {
    const fields = {};
    for (const [k, v] of Object.entries(value)) {
      fields[k] = toFirestoreValue(v);
    }
    return { mapValue: { fields } };
  }
  return { stringValue: String(value) };
}

function toFirestoreDocument(obj) {
  const fields = {};
  for (const [k, v] of Object.entries(obj)) {
    fields[k] = toFirestoreValue(v);
  }
  return { fields };
}

const firestoreBody = toFirestoreDocument(sinergyDoc);

return [{ json: { firestoreBody, sinergyDoc } }];

// ---- Build a signed JWT for Google Service Account ----
// IMPORTANT: In production use n8n's built-in Google Service
// Account credential type instead of this node.
// This node is here as a transparent reference implementation.
//
// To use native credentials:
//   1. Go to n8n Credentials → New → Google API
//   2. Choose 'Service Account' auth type
//   3. Paste your service account JSON
//   4. Set scope: https://www.googleapis.com/auth/datastore
//   5. Delete this Code node and the 'Firebase Auth' HTTP node
//   6. In the Firestore PATCH node select that credential.

// Retrieve the service account JSON stored as an n8n credential
// expression (set the credential value in n8n as a JSON string).
// For now we use environment / workflow variables as placeholders.

// ---- PLACEHOLDER — replace with real values ----
const SERVICE_ACCOUNT_EMAIL  = 'YOUR_SERVICE_ACCOUNT@titas-sinergy.iam.gserviceaccount.com';
const PRIVATE_KEY_PEM        = '-----BEGIN RSA PRIVATE KEY-----\nPASTE_YOUR_PRIVATE_KEY_HERE\n-----END RSA PRIVATE KEY-----';
// ------------------------------------------------

const scope  = 'https://www.googleapis.com/auth/datastore';
const aud    = 'https://oauth2.googleapis.com/token';
const iat    = Math.floor(Date.now() / 1000);
const exp    = iat + 3600;

// Base64URL encode
const b64url = (str) => Buffer.from(str).toString('base64')
  .replace(/\+/g, '-').replace(/\//g, '_').replace(/=/g, '');

const header  = b64url(JSON.stringify({ alg: 'RS256', typ: 'JWT' }));
const payload = b64url(JSON.stringify({ iss: SERVICE_ACCOUNT_EMAIL, scope, aud, exp, iat }));

// NOTE: n8n's Code node runs in a sandboxed environment without
// access to Node's crypto module for RSA signing.
// The recommended approach is to use the native Google credential.
// This placeholder returns the unsigned parts so you can verify
// the structure; the Firebase Auth HTTP node above will not
// work until you replace it with a proper credential.
const jwt_assertion = `${header}.${payload}.SIGNATURE_PLACEHOLDER`;

// Pass through the Firestore body from the previous step
const firestoreBody = $('Transformar Dados CDC → Sinergy').first().json.firestoreBody;

return [{ json: { jwt_assertion, firestoreBody } }];

